// Calculate follow-up dates for all leads
const items = $input.all();
const result = [];

for (const item of items) {
  const now = new Date();

  // Set follow-up dates: Day 3, Day 7, Day 14
  const followUp1Date = new Date(now.getTime() + (3 * 24 * 60 * 60 * 1000));
  const followUp2Date = new Date(now.getTime() + (7 * 24 * 60 * 60 * 1000));
  const breakupDate = new Date(now.getTime() + (14 * 24 * 60 * 60 * 1000));

  result.push({
    json: {
      ...item.json,
      FollowUp1Due: followUp1Date.toISOString().split('T')[0],
      FollowUp2Due: followUp2Date.toISOString().split('T')[0],
      BreakupDue: breakupDate.toISOString().split('T')[0]
    }
  });
}

return result;

